import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Calendar from './Calendar';
import EventModal from './EventModal';
import Login from './Login';
import Register from './Register';
import axios from './axiosConfig';
import './App.css';

function App() {
  const routerBaseName = process.env.PUBLIC_URL || '/';
  const [events, setEvents] = useState([]);
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [user, setUser] = useState(null);
  const [authLoading, setAuthLoading] = useState(true);

  useEffect(() => {
    checkAuth();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (user) {
      fetchEvents();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentMonth, user]);

  const checkAuth = async () => {
    try {
      const response = await axios.get('/auth/check');
      if (response.data?.token) {
        localStorage.setItem('authToken', response.data.token);
      }
      setUser(response.data.user);
    } catch (error) {
      localStorage.removeItem('authToken');
      setUser(null);
    } finally {
      setAuthLoading(false);
    }
  };

  const handleLogin = (userData) => {
    setUser(userData);
  };

  const handleLogout = async () => {
    try {
      await axios.post('/logout');
    } catch (error) {
      console.error('Logout error:', error);
    } finally {
      localStorage.removeItem('authToken');
      setUser(null);
    }
  };

  const fetchEvents = async () => {
    try {
      const year = currentMonth.getFullYear();
      const month = currentMonth.getMonth() + 1;
      const response = await axios.get(`/events?year=${year}&month=${month}`);
      setEvents(response.data);
    } catch (error) {
      console.error('Error fetching events:', error);
    }
  };

  const handleDateClick = (date) => {
    setSelectedDate(date);
    setSelectedEvent(null);
    setIsModalOpen(true);
  };

  const handleEventClick = (event) => {
    setSelectedEvent(event);
    setSelectedDate(new Date(event.start_date));
    setIsModalOpen(true);
  };

  const handleSaveEvent = async (eventData) => {
    try {
      if (selectedEvent) {
        await axios.put(`/events/${selectedEvent.id}`, eventData);
      } else {
        await axios.post('/events', eventData);
      }
      fetchEvents();
      setIsModalOpen(false);
    } catch (error) {
      console.error('Error saving event:', error);
    }
  };

  const handleDeleteEvent = async (eventId) => {
    try {
      await axios.delete(`/events/${eventId}`);
      fetchEvents();
      setIsModalOpen(false);
    } catch (error) {
      console.error('Error deleting event:', error);
    }
  };

  if (authLoading) {
    return <div className="loading-container"><p>加载中...</p></div>;
  }

  return (
    <Router basename={routerBaseName}>
      <div className="App">
        <Routes>
          <Route path="/login" element={user ? <Navigate to="/" replace /> : <Login onLogin={handleLogin} />} />
          <Route path="/register" element={user ? <Navigate to="/" replace /> : <Register onLogin={handleLogin} />} />
          <Route
            path="/"
            element={
              user ? (
                <>
                  <header className="app-header">
                    <h1>📅 日历应用</h1>
                    <button className="logout-btn" onClick={handleLogout}>退出登录</button>
                  </header>
                  <main>
                    <Calendar
                      events={events}
                      onDateClick={handleDateClick}
                      onEventClick={handleEventClick}
                      currentMonth={currentMonth}
                      setCurrentMonth={setCurrentMonth}
                    />
                    <EventModal
                      isOpen={isModalOpen}
                      onClose={() => setIsModalOpen(false)}
                      onSave={handleSaveEvent}
                      onDelete={handleDeleteEvent}
                      selectedDate={selectedDate}
                      event={selectedEvent}
                    />
                  </main>
                </>
              ) : (
                <Navigate to="/login" replace />
              )
            }
          />
        </Routes>
      </div>
    </Router>
  );
}

export default App;