import axios from 'axios';

const isGithubPages = typeof window !== 'undefined' && window.location.hostname.endsWith('github.io');
const productionApiFallback = 'https://calendar-app-production-f9ec.up.railway.app/api';

// 配置axios默认设置
axios.defaults.baseURL = process.env.REACT_APP_API_BASE_URL || (isGithubPages ? productionApiFallback : 'http://localhost:5000/api');
axios.defaults.withCredentials = true; // 允许发送cookies
axios.defaults.headers.common['Content-Type'] = 'application/json';

axios.interceptors.request.use((config) => {
	const token = localStorage.getItem('authToken');
	if (token) {
		config.headers = config.headers || {};
		config.headers.Authorization = `Bearer ${token}`;
	}
	return config;
});

export default axios;